import boto3
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from flask import Flask, request, jsonify
import os

app = Flask(__name__)

s3 = boto3.client('s3', region_name='your-region', aws_access_key_id='your-access-key-id', aws_secret_access_key='your-secret-access-key')

def take_screenshot(url):
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")

    driver = webdriver.Chrome(options=chrome_options)
    driver.set_window_size(1280, 720)
    driver.get(url)
    screenshot_path = '/tmp/screenshot.png'
    driver.save_screenshot(screenshot_path)
    driver.quit()
    return screenshot_path

def upload_to_s3(file_path, bucket_name, object_name):
    s3.upload_file(file_path, bucket_name, object_name)
    return f"https://{bucket_name}.s3.amazonaws.com/{object_name}"

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.json
    url = data.get('url')
    if not url:
        return jsonify({'error': 'URL is required'}), 400

    try:
        screenshot_path = take_screenshot(url)
        object_name = os.path.basename(screenshot_path)
        bucket_name = 'your-s3-bucket-name'
        s3_url = upload_to_s3(screenshot_path, bucket_name, object_name)
        return jsonify({'s3_url': s3_url}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

